109→    private void autoSelectNewestFiles() {
110→        // 自动选择Download/Weixin目录中最新的一对文件（音频+文档）
111→        new Thread(() -> {
112→            try {
113→                File downloadDir = new File(Environment.getExternalStorageDirectory(), "Download");
114→                File weixinDir = new File(downloadDir, "Weixin");
115→                File targetDir = weixinDir.exists() ? weixinDir : downloadDir;
116→
117→                File[] files = targetDir.listFiles();
118→                if (files == null || files.length == 0) return;
119→
120→                // 按修改时间排序，最新的在前
121→                java.util.Arrays.sort(files, (a, b) -> Long.compare(b.lastModified(), a.lastModified()));
122→
123→                File newestAudio = null;
124→                File newestDoc = null;
125→
126→                // 找最新的音频和文档
127→                for (File f : files) {
128→                    String name = f.getName().toLowerCase();
129→                    if (newestAudio == null && isAudioFile(name)) {
130→                        newestAudio = f;
131→                    } else if (newestDoc == null && isDocFile(name)) {
132→                        newestDoc = f;
133→                    }
134→                    if (newestAudio != null && newestDoc != null) break;
135→                }
136→
137→                // 自动填充
138→                if (newestAudio != null) {
139→                    String path = newestAudio.getAbsolutePath();
140→                    audioPath = path;
141→                    final String name = newestAudio.getName();
142→                    runOnUiThread(() -> tvAudioName.setText(name));
143→                    Log.i(TAG, "自动选择音频: " + name);
144→                }
145→                if (newestDoc != null) {
146→                    String path = newestDoc.getAbsolutePath();
147→                    docPath = path;
148→                    final String name = newestDoc.getName();
149→                    runOnUiThread(() -> tvDocName.setText(name));
150→                    Log.i(TAG, "自动选择文档: " + name);
151→                }
152→            } catch (Exception e) {
153→                Log.e(TAG, "自动选择文件失败", e);
154→            }
155→        }).start();
156→    }
