158→    private boolean isAudioFile(String name) {
159→        return name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
160→               name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk") ||
161→               name.endsWith(".ogg") || name.endsWith(".opus") || name.endsWith(".aac");
162→    }
