342→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
343→    private float[] decodeAudio(String filepath) throws Exception {
344→        MediaExtractor extractor = new MediaExtractor();
345→        extractor.setDataSource(filepath);
346→
347→        // 查找音频轨道
348→        int trackIndex = -1;
349→        MediaFormat format = null;
350→        for (int i = 0; i < extractor.getTrackCount(); i++) {
351→            MediaFormat f = extractor.getTrackFormat(i);
352→            String mime = f.getString(MediaFormat.KEY_MIME);
353→            if (mime != null && mime.startsWith("audio/")) {
354→                trackIndex = i;
355→                format = f;
356→                break;
357→            }
358→        }
359→        if (trackIndex < 0) {
360→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
361→        }
362→
363→        extractor.selectTrack(trackIndex);
364→        String mime = format.getString(MediaFormat.KEY_MIME);
365→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
366→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
367→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
368→
369→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
370→
371→        if ("audio/raw".equals(mime)) {
372→            // PCM WAV: 直接从extractor读取，不需要codec解码
373→            ByteBuffer buf = ByteBuffer.allocate(65536);
374→            while (extractor.readSampleData(buf, 0) >= 0) {
375→                int pos = buf.position();
376→                byte[] chunk = new byte[pos];
377→                buf.flip();
378→                buf.get(chunk);
379→                pcmOut.write(chunk);
380→                buf.clear();
381→                extractor.advance();
382→            }
383→        } else {
384→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
385→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
386→            codec.configure(format, null, null, 0);
387→            codec.start();
388→
389→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
390→            boolean inputDone = false;
391→            boolean outputDone = false;
392→
393→            while (!outputDone) {
394→                // 送入压缩数据
395→                if (!inputDone) {
396→                    int inputIdx = codec.dequeueInputBuffer(10000);
397→                    if (inputIdx >= 0) {
398→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
399→                        int size = extractor.readSampleData(inputBuf, 0);
400→                        if (size < 0) {
401→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
402→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
403→                            inputDone = true;
404→                        } else {
405→                            codec.queueInputBuffer(inputIdx, 0, size,
406→                                extractor.getSampleTime(), 0);
407→                            extractor.advance();
408→                        }
409→                    }
410→                }
411→
412→                // 取出PCM数据
413→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
414→                if (outputIdx >= 0) {
415→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
416→                        outputDone = true;
417→                    }
418→                    if (info.size > 0) {
419→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
420→                        byte[] chunk = new byte[info.size];
421→                        outputBuf.get(chunk);
422→                        pcmOut.write(chunk);
423→                    }
424→                    codec.releaseOutputBuffer(outputIdx, false);
425→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
426→                    MediaFormat outFmt = codec.getOutputFormat();
427→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
428→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
429→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
430→                }
431→            }
432→
433→            codec.stop();
434→            codec.release();
435→        }
436→
437→        extractor.release();
438→
439→        byte[] pcmBytes = pcmOut.toByteArray();
440→        if (pcmBytes.length < 100) {
441→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
442→        }
443→
444→        // PCM bytes -> float samples (16-bit little-endian)
445→        int numSamples = pcmBytes.length / 2;
446→        float[] allSamples = new float[numSamples];
447→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
448→        for (int i = 0; i < numSamples; i++) {
449→            allSamples[i] = bb.getShort() / 32768.0f;
450→        }
451→
452→        // 立体声 -> 单声道
453→        float[] mono;
454→        if (channels > 1) {
455→            int monoLen = numSamples / channels;
456→            mono = new float[monoLen];
457→            for (int i = 0; i < monoLen; i++) {
458→                float sum = 0;
459→                for (int c = 0; c < channels; c++) {
460→                    sum += allSamples[i * channels + c];
461→                }
462→                mono[i] = sum / channels;
463→            }
464→        } else {
465→            mono = allSamples;
466→        }
467→
468→        // 重采样到16kHz
469→        if (sampleRate != 16000) {
470→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
471→            mono = resample(mono, sampleRate, 16000);
472→        }
473→
474→        float durationSec = mono.length / 16000.0f;
475→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
476→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
477→
478→        if (durationSec < 0.3f) {
479→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
480→        }
481→
482→        return mono;
483→    }
