503→    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
504→    private String transcribeSherpa(String audioFile) throws Exception {
505→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
506→        float[] samples = decodeAudio(audioFile);
507→        lastAudioDuration = samples.length / 16000.0f;  // 记录音频时长
508→
509→        AssetManager assetManager = getAssets();
510→
511→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
512→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
513→
514→        OfflineModelConfig modelConfig = new OfflineModelConfig();
515→        modelConfig.setParaformer(paraformerConfig);
516→        modelConfig.setTokens("models/paraformer/tokens.txt");
517→        modelConfig.setNumThreads(4);
518→        modelConfig.setDebug(false);
519→
520→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
521→        config.setModelConfig(modelConfig);
522→        config.setDecodingMethod("greedy_search");
523→
524→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
525→
526→        // 分段识别：每段30秒，提高长音频准确率
527→        int chunkSamples = 30 * 16000;
528→        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
529→        StringBuilder allText = new StringBuilder();
530→
531→        if (totalChunks <= 1) {
532→            // 短音频直接识别
533→            OfflineStream stream = recognizer.createStream();
534→            stream.acceptWaveform(samples, 16000);
535→            recognizer.decode(stream);
536→            OfflineRecognizerResult result = recognizer.getResult(stream);
537→            allText.append(result.getText() != null ? result.getText().trim() : "");
538→            stream.release();
539→        } else {
540→            // 长音频分段识别
541→            for (int ci = 0; ci < totalChunks; ci++) {
542→                int finalCi = ci;
543→                runOnUiThread(() -> tvStatus.setText(
544→                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));
545→
546→                int start = ci * chunkSamples;
547→                // 加1秒重叠避免截断
548→                int overlap = ci > 0 ? 16000 : 0;
549→                int actualStart = Math.max(0, start - overlap);
550→                int end = Math.min(samples.length, start + chunkSamples);
551→                int len = end - actualStart;
552→
553→                if (len < 1600) continue; // 不足0.1秒跳过
554→
555→                float[] chunk = new float[len];
556→                System.arraycopy(samples, actualStart, chunk, 0, len);
557→
558→                OfflineStream stream = recognizer.createStream();
559→                stream.acceptWaveform(chunk, 16000);
560→                recognizer.decode(stream);
561→                OfflineRecognizerResult result = recognizer.getResult(stream);
562→                String text = result.getText() != null ? result.getText().trim() : "";
563→
564→                if (!text.isEmpty()) {
565→                    // 去除重叠部分导致的重复（最长公共后缀/前缀匹配，窗口30字）
566→                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
567→                        String prev = allText.toString();
568→                        int maxCheck = Math.min(30, Math.min(prev.length(), text.length()));
569→                        int bestMatch = 0;
570→                        for (int t = maxCheck; t > 0; t--) {
571→                            if (prev.endsWith(text.substring(0, t))) {
572→                                bestMatch = t;
573→                                break;
574→                            }
575→                        }
576→                        if (bestMatch > 0) {
577→                            text = text.substring(bestMatch);
578→                        }
579→                    }
580→                    allText.append(text);
581→                }
582→                stream.release();
583→            }
584→        }
585→
586→        recognizer.release();
587→        return allText.toString().trim();
588→    }
